package contracts

import (
	"encoding/hex"
	"math/big"
)

// Contract bytecodes — compiled from Solidity sources.
// These must be generated by compiling the actual contracts.
// For now, we provide a placeholder mechanism that loads from files or embeds.

// NOTE: These bytecodes need to be populated by running:
//   solc --optimize --bin contracts/ERC20Template.sol
// Then pasting the hex output here.
// When bytecodes are not available, the test framework will report SKIP for deploy tests.

// mustDecodeHex decodes hex or panics.
func mustDecodeHex(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic("invalid bytecode hex: " + err.Error())
	}
	return b
}

