// EncodeERC20Constructor encodes constructor args for ERC20Template.
// constructor(string _name, string _symbol, uint8 _decimals, uint256 _initialSupply)
func EncodeERC20Constructor(name, symbol string, decimals uint8, initialSupply *big.Int) []byte {
	// ABI encode: 4 dynamic/static params
	// offset_name (32) | offset_symbol (32) | decimals (32) | initialSupply (32) | name_data | symbol_data

	nameBytes := []byte(name)
	symbolBytes := []byte(symbol)

	namePadded := len(nameBytes)
	if namePadded%32 != 0 {
		namePadded += 32 - (namePadded % 32)
	}
	symbolPadded := len(symbolBytes)
	if symbolPadded%32 != 0 {
		symbolPadded += 32 - (symbolPadded % 32)
	}

	// Fixed params first, then dynamic data
	// Param layout: [offset_name, offset_symbol, decimals, initialSupply, name_len, name_data, symbol_len, symbol_data]
	// offset_name = 4*32 = 128 (after 4 fixed-size slots)
	// offset_symbol = 128 + 32 + namePadded

	offsetName := big.NewInt(int64(4 * 32))
	offsetSymbol := big.NewInt(int64(4*32 + 32 + namePadded))

	var result []byte
	result = append(result, EncodeUint256(offsetName)...)
	result = append(result, EncodeUint256(offsetSymbol)...)
	result = append(result, EncodeUint256(big.NewInt(int64(decimals)))...)
	result = append(result, EncodeUint256(initialSupply)...)

	// Name
	result = append(result, EncodeUint256(big.NewInt(int64(len(nameBytes))))...)
	padName := make([]byte, namePadded)
	copy(padName, nameBytes)
	result = append(result, padName...)

	// Symbol
	result = append(result, EncodeUint256(big.NewInt(int64(len(symbolBytes))))...)
	padSymbol := make([]byte, symbolPadded)
	copy(padSymbol, symbolBytes)
	result = append(result, padSymbol...)

	return result
}

// BytecodesAvailable returns true if contract bytecodes have been loaded.
func BytecodesAvailable() bool {
	return len(ERC20TemplateBytecode) > 0
}

